+    var days: i64 = 0;
+    var y: i32 = 1970;
+    while (y < year) : (y += 1) {
+        days += if (isleap(y)) 366 else 365;
+    }
+    var m: i32 = 1;
+    while (m < mon) : (m += 1) {
+        days += daysInMonth(year, m);
+    }
+    days += day - 1;
