+/// Return the arithmetic mean of numeric data.
+pub fn mean(comptime T: type, data: []const T) !f64 {
+    if (data.len == 0) return StatisticsError.EmptyData;
+
+    var sum: f64 = 0;
+    for (data) |x| {
+        sum += toFloat(x);
+    }
+    return sum / @as(f64, @floatFromInt(data.len));
