+    for (data) |x| {
+        const val = toFloat(x);
+        if (val <= 0) return error.InvalidValue;
+        reciprocal_sum += 1.0 / val;
+    }
+    return @as(f64, @floatFromInt(data.len)) / reciprocal_sum;
