+    for (data, 0..) |x, i| {
+        sorted[i] = toFloat(x);
+    }
+    std.mem.sort(f64, sorted, {}, std.sort.asc(f64));
+
+    const n = sorted.len;
+    if (n % 2 == 1) {
+        return sorted[n / 2];
+    } else {
+        return (sorted[n / 2 - 1] + sorted[n / 2]) / 2.0;
+    }
