+    var numerator: f64 = 0;
+    var sum_sq_x: f64 = 0;
+    var sum_sq_y: f64 = 0;
+
+    for (x, y) |xi, yi| {
+        const dx = toFloat(xi) - mean_x;
+        const dy = toFloat(yi) - mean_y;
+        numerator += dx * dy;
+        sum_sq_x += dx * dx;
+        sum_sq_y += dy * dy;
+    }
